const input = $input.first().json || {};
const payload = input.payload == null
  ? {}
  : (typeof input.payload === 'string' ? JSON.parse(input.payload) : input.payload);
const tenant_id = input.tenant_id || payload.tenant_id || null;
const correlation_id = input.correlation_id || payload.correlation_id || null;
if (!correlation_id) throw new Error('telegram-approve: missing correlation_id');
const service = input.service || payload.service || 'approval';
const step = input.step || payload.step || 'approval';
const timeout_hours = Number(input.timeout_hours ?? payload.timeout_hours ?? 24);
const approver = input.approver || payload.approver || null;
const second_approver = input.second_approver || payload.second_approver || null;
const text = input.text || payload.text || [
  'Approval requested',
  'Service: ' + service + '/' + step,
  'Correlation: `' + correlation_id + '`'
].join('\n');
return [{ json: {
  tenant_id,
  correlation_id,
  service,
  step,
  text,
  parse_mode: input.parse_mode || 'Markdown',
  chat_id: input.chat_id || $env.TELEGRAM_CHAT_ID || '',
  timeout_hours: Number.isFinite(timeout_hours) && timeout_hours > 0 ? timeout_hours : 24,
  approve_label: input.approve_label || 'Approve',
  reject_label: input.reject_label || 'Reject',
  approver,
  second_approver,
  payload
} }];

const p = $('Normalize Approval Input').first().json;
function publicResumeUrl(raw) {
  const publicBase = ($env.WEBHOOK_URL || $env.N8N_DOMAIN || '').replace(/\/$/, '');
  if (!publicBase) return raw;
  try {
    const source = new URL(raw);
    const base = new URL(publicBase);
    return base.origin + source.pathname + source.search + source.hash;
  } catch (e) {
    return raw;
  }
}
const approvalUrl = publicResumeUrl($execution.resumeUrl);
const sep = approvalUrl.includes('?') ? '&' : '?';
const payload = {
  ...(p.payload || {}),
  approver: p.approver,
  second_approver: p.second_approver,
  approval_url: approvalUrl,
  approve_url: approvalUrl + sep + 'decision=approve',
  reject_url: approvalUrl + sep + 'decision=reject',
  timeout_hours: p.timeout_hours
};
return [{ json: {
  tenant_id: p.tenant_id,
  correlation_id: p.correlation_id,
  service: p.service,
  step: p.step,
  status: 'waiting',
  payload
} }];

const p = $('Normalize Approval Input').first().json;
const waiting = $('Prep Audit: Waiting').first().json;
const token = $env.TELEGRAM_BOT_TOKEN || '';
const chat = p.chat_id || '';
if (!token) throw new Error('telegram-approve: TELEGRAM_BOT_TOKEN not set');
if (!chat) throw new Error('telegram-approve: TELEGRAM_CHAT_ID/chat_id not set');
const body = {
  chat_id: chat,
  text: p.text,
  reply_markup: {
    inline_keyboard: [[
      { text: p.approve_label, url: waiting.payload.approve_url },
      { text: p.reject_label, url: waiting.payload.reject_url }
    ]]
  }
};
if (p.parse_mode) body.parse_mode = p.parse_mode;
try {
  const sent = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.telegram.org/bot' + token + '/sendMessage',
    body,
    json: true,
    timeout: 15000
  });
  return [{ json: { ...p, telegram_delivered: true, telegram_message_id: sent && sent.result ? sent.result.message_id : null } }];
} catch (e) {
  const raw = String(e && e.message ? e.message : e).split(token).join('[token]');
  throw new Error('telegram-approve: telegram send failed: ' + raw.slice(0, 500));
}

const p = $('Send Approval Request').first().json;
const query = $json.query || {};
const rawDecision = String(query.decision || '').toLowerCase();
const decision = rawDecision === 'approve' ? 'approve' : (rawDecision === 'reject' ? 'reject' : 'timeout');
return [{ json: {
  tenant_id: p.tenant_id,
  correlation_id: p.correlation_id,
  service: p.service,
  step: p.step,
  decision,
  approved: decision === 'approve',
  rejected: decision === 'reject',
  timed_out: decision === 'timeout',
  approver: p.approver,
  second_approver: p.second_approver,
  telegram_delivered: p.telegram_delivered,
  telegram_message_id: p.telegram_message_id
} }];
